  ('locality-6f0ba476-moex-00276', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '法人、合夥或非法人團體解散清算時，尚未繳清之稅捐，應如何處理？', '["清算人於分配賸餘財產前，應依法按稅捐受清償之順序，繳清稅捐", "清算人於分配賸餘財產前，應依欠稅金額由高至低順序，繳清稅捐", "負責人於分配賸餘財產前，應依法按稅捐受清償之順序，繳清稅捐", "負責人於分配賸餘財產前，應依欠稅金額由高至低順序，繳清稅捐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00277', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '納稅義務人如發現繳納通知文書將房屋稅計算錯誤時，應如何處理？', '["於繳納期限屆滿後30日內，向稅捐稽徵機關進行查對更正", "於繳納期限屆滿後30日內，向稅捐稽徵機關進行復查", "於規定繳納期間內，向稅捐稽徵機關進行查對更正", "於規定繳納期間內，向稅捐稽徵機關進行復查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00278', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵機關對逃漏那些稅捐，認為涉有犯罪嫌疑之案件，得聲請司法機關簽發搜索票後，進入 處所實施搜查？', '["所得稅、營業稅、貨物稅", "營業稅、土增稅、印花稅", "營業稅、貨物稅、遺贈稅", "所得稅、印花稅、娛樂稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00279', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '所得稅法有關「災害損失」扣除之規定，下列敘述何者正確？①不論是否受有保險賠償或救濟金', '["指納稅義務人、配偶或受扶養親屬遭受不可抗力之災害", "災害，指地震、 風災、水災、旱災、蟲災、火災、竊盜及戰禍等", "應於災害發生後30日內檢具損失清單及證明 文件，報請該管稽徵機關派員勘查", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00280', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，有關房地合一課徵所得稅制度之規定，下列敘述何者正確？', '["若所計算之房地合一交易所得之應納稅額為零，則不需依規定於期限內辦理房地合一稅之申報", "個人違反第14條之5規定，未依限辦理房地交易所得申報，處新臺幣3千元以上3萬元以下 之罰鍰", "個人已依規定辦理房屋、土地交易所得申報，有漏報或短報情事，處以所漏稅額 20%以下之 罰鍰", "符合自用住宅課稅要件之房地可免徵土地增值稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00281', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '營利事業遇有解散、廢止、合併或轉讓情事時，應於截至解散、廢止、合併或轉讓之日起多久內， 向該管稽徵機關辦理當期營利事業所得稅之決算申報？', '["30日", "45日", "60日", "90日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00282', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，下列有關營利事業交際應酬費之規定，何者錯誤？', '["營利事業委託會計師查核簽證申報者可列支之交際費較採普通申報者高", "取得外匯收入之外銷業務，除依規定列支交際費，並得在不超過當年度外銷結匯收入總額 2% 內列支特別交際費", "民營事業各項交際應酬費用支付之限度，由各行業別自行訂定，並報財政部核定", "公營事業各項交際應酬費用支付之限度，由主管機關分別核定，列入預算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00283', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依所得稅法有關暫繳之規定，下列敘述何者正確？', '["採曆年制之營利事業，應於8月1日至8月31日作暫繳申報", "採七月制之營利事業，應於4月1日至4月30日作暫繳申報", "會計帳簿完備之營利事業，逾期辦理暫繳申報者，得採試算暫繳計算稅額", "營利事業未依規定辦理暫繳申報，稽徵機關應加計利息但免處罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00284', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依所得基本稅額條例規定，個人基本所得額之計算係由綜合所得淨額加計之項目，不包括下列 何者？', '["受益人與要保人不同人之死亡人壽保險給付新臺幣1,000萬元", "符合所得基本稅額條例第12條之1規定之營利所得新臺幣500萬元", "非現金之捐贈扣除額新臺幣500萬元", "私募證券投資信託基金受益憑證之交易所得新臺幣500萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
